const raw = $input.first().json || {};
const text = String(raw.spec || raw.conteudo || raw.content || '').trim();
const title = String(raw.titulo || raw.title || raw.nome || 'SPEC sem titulo').trim().slice(0, 160);
const domain = String(raw.dominio || raw.domain || 'FabioOS').trim();
const phase = String(raw.fase || raw.phase || '').trim();
const requester = String(raw.solicitante || raw.requester || 'Fabio').trim();
const requestId = raw.request_id || `spec_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
return [{ json: {
  request_id: requestId,
  received_at: new Date().toISOString(),
  title,
  domain,
  phase,
  requester,
  spec_text: text,
  raw_keys: Object.keys(raw),
  status: 'normalized'
}}];

const item = $input.first().json;
const text = `${item.title}\n${item.spec_text}`;
const lower = text.toLowerCase();
const missing = [];
if (!item.spec_text || item.spec_text.length < 20) missing.push('spec_texto_curto');
if (!/(objetivo|objective|resultado)/i.test(text)) missing.push('objetivo');
if (!/(fora de escopo|out of scope|nao fazer|não fazer)/i.test(text)) missing.push('fora_de_escopo');
if (!/(criterio|critério|aceite|acceptance)/i.test(text)) missing.push('criterios_de_aceite');
if (!/(teste|validacao|validação)/i.test(text)) missing.push('testes');
if (!/(risco|risk)/i.test(text)) missing.push('riscos');
let excellence_gate = missing.length === 0 ? 'pass' : 'needs_refinement';
let permission = 'propose_only';
if (/(whatsapp|email|push|deploy|pagamento|trade|apagar|delete|token|credencial)/i.test(lower)) permission = 'human_approval_required';
return [{ json: {...item, missing_sections: missing, excellence_gate, permission, status: 'excellence_checked'} }];

const item = $input.first().json;
const lower = `${item.title}\n${item.spec_text}`.toLowerCase();
let complexity = 'media';
if (item.spec_text.length < 800) complexity = 'baixa';
if (item.spec_text.length > 2500 || /(multiagente|runtime|api externa|whatsapp|mcp|rag|grafo|deploy)/i.test(lower)) complexity = 'alta';
const tasks = [];
tasks.push({id: 'T1', owner: 'Codex', task: 'Formalizar SPEC e criterios de aceite', zone: 'documentacao'});
tasks.push({id: 'T2', owner: 'Claude', task: 'Validar arquitetura e contrato tecnico', zone: 'arquitetura'});
if (/(interface|dashboard|visual|html|render|apresentacao|apresentação)/i.test(lower)) tasks.push({id: 'T3', owner: 'Cursor', task: 'Prototipar apresentacao/interface consumindo contrato', zone: 'interface'});
if (/(n8n|workflow|automacao|automação|webhook)/i.test(lower)) tasks.push({id: 'T4', owner: 'Codex', task: 'Criar workflow n8n inativo e documentado', zone: 'automacao_documentada'});
if (/(rag|busca semantica|fonte|fontes)/i.test(lower)) tasks.push({id: 'T5', owner: 'Claude', task: 'Validar uso RAG read-only sem reindex', zone: 'rag_read_only'});
if (/(openclaw|whatsapp|evolution)/i.test(lower)) tasks.push({id: 'T6', owner: 'Cursor/OpenClaw', task: 'Validar canal visual sem envio real', zone: 'runtime_bloqueado'});
return [{ json: {...item, complexity, tasks, status: 'decomposed'} }];

const item = $input.first().json;
const lower = `${item.title}\n${item.spec_text}`.toLowerCase();
const gates = [
  'Nao expor tokens ou credenciais',
  'Sem push sem aprovacao humana',
  'Sem apagar conhecimento',
  'Sem acao externa sem autorizacao',
  'Changelog obrigatorio',
  'Scan de segredos antes de commit'
];
if (/(rag|mcp|grafo)/i.test(lower)) gates.push('Uso RAG/MCP/Grafo somente read-only salvo handoff explicito');
if (/(n8n|openclaw|whatsapp|email)/i.test(lower)) gates.push('Runtime externo permanece inativo ou Fabio-gated');
if (/(codigo|script|python|workflow)/i.test(lower)) gates.push('Teste minimo local ou validacao sintatica obrigatoria');
return [{ json: {...item, quality_gates: gates, status: 'gated'} }];

const item = $input.first().json;
const acceptance = [
  'Artefato versionavel no vault',
  'Visivel no Obsidian',
  'Sem credenciais expostas',
  'Possui changelog',
  'Possui rollback ou criterio de desligamento'
];
if (item.excellence_gate !== 'pass') acceptance.unshift(`SPEC refinada: corrigir secoes ausentes (${item.missing_sections.join(', ')})`);
const tests = [
  'Validar JSON/Markdown quando aplicavel',
  'Rodar scan de segredos',
  'Conferir git diff --check',
  'Conferir que arquivos de outras frentes nao entraram no stage'
];
return [{ json: {...item, acceptance, tests, status: 'acceptance_ready'} }];
